try {
  // Realiza a chamada HTTP para o backend do K-Desk para buscar artigos da base filtrados.
  // Ajuste a URL para o seu endpoint da Vercel ou ambiente de desenvolvimento local.
  const query = args.query || '';
  const response = await fetch('https://k-desk.vercel.app/api/chat', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      description: query,
      chat_context: []
    })
  });
  const data = await response.json();
  return JSON.stringify(data);
} catch (error) {
  return JSON.stringify({
    error: 'Falha ao buscar base de conhecimento: ' + error.message
  });
}

try {
  // Registra o ticket de suporte diretamente na API do K-Desk.
  // Ajuste a URL para o endereço real de sua hospedagem ou localhost.
  const response = await fetch('https://k-desk.vercel.app/api/triage', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      requester_name: args.requester_name || 'Usuário via n8n',
      requester_email: args.requester_email || 'n8n@kdesk.corp',
      description: args.description || '',
      answers: {
        troubleshooting_summary: args.troubleshooting_summary || '',
        kb_article_id: args.kb_article_id || ''
      }
    })
  });
  const data = await response.json();
  return JSON.stringify(data);
} catch (error) {
  return JSON.stringify({
    error: 'Erro de conexao ao salvar o ticket: ' + error.message
  });
}
